head.b:skin:
@import url('https://fonts.googleapis.com/css2?family=Plus+Jakarta+Sans:wght;400;600;800&family=Hind+Siliguri:wght;400;600;700&display=swap');

:root {
    --primary: #d4af37; /* Royal Gold */
    --primary-dark: #b8960c;
    --bg-dark: #0a0e14; 
    --bg-darker: #05070a;
    --card-bg: rgba(22, 27, 34, 0.8);
    --text-white: #ffffff;
    --text-muted: #94a3b8;
    --border: rgba(212, 175, 55, 0.15);
    --border-light: rgba(255,255,255,0.05);
    --gradient-main: linear-gradient(135deg, #d4af37 0%, #fcf6ba 50%, #d4af37 100%);
    --shadow-sm: 0 5px 20px rgba(0,0,0,0.3);
    --shadow-lg: 0 20px 50px rgba(0,0,0,0.5);
    --transition: all 0.3s ease;
}

* { box-sizing: border-box; scroll-behavior: smooth; }
body { font-family: 'Plus Jakarta Sans', 'Hind Siliguri', sans-serif; margin: 0; background-color: var(--bg-dark); color: var(--text-white); overflow-x: hidden; line-height: 1.6; }
a { text-decoration: none; }

/* --- UTILITIES --- */
.section-padding { padding: 100px 5%; position: relative; }
.container { max-width: 1280px; margin: 0 auto; }
.section-header { text-align: center; margin-bottom: 70px; }
.section-header h2 { font-size: 42px; font-weight: 800; margin: 0 0 15px 0; }
.section-header h2 span { color: var(--primary); background: var(--gradient-main); -webkit-background-clip: text; -webkit-text-fill-color: transparent; }
.section-header p { color: var(--text-muted); font-size: 18px; max-width: 600px; margin: 0 auto; }
.btn-primary { display: inline-block; background: var(--gradient-main); color: #000; padding: 15px 40px; border-radius: 50px; font-weight: 800; font-size: 16px; box-shadow: 0 10px 30px rgba(212, 175, 55, 0.3); transition: var(--transition); border: none; cursor: pointer; }
.btn-primary:hover { transform: translateY(-3px); box-shadow: 0 15px 40px rgba(212, 175, 55, 0.5); }
.btn-outline { display: inline-block; background: transparent; color: var(--primary); padding: 13px 40px; border-radius: 50px; font-weight: 800; font-size: 16px; border: 2px solid var(--primary); transition: var(--transition); }
.btn-outline:hover { background: var(--primary); color: #000; }

/* --- BREAKING NEWS TICKER --- */
.news-ticker-wrapper { background: var(--bg-darker); border-bottom: 1px solid var(--primary); padding: 8px 5%; position: relative; z-index: 1001; margin-top: 80px; }
.ticker-container { display: flex; align-items: center; gap: 20px; max-width: 1280px; margin: 0 auto; }
.ticker-label { background: var(--primary); color: #000; padding: 6px 20px; border-radius: 40px; font-weight: 800; font-size: 14px; text-transform: uppercase; letter-spacing: 1px; white-space: nowrap; box-shadow: 0 0 15px rgba(212,175,55,0.5); }
.ticker-content { overflow: hidden; flex: 1; }
.ticker-marquee { display: flex; gap: 40px; animation: tickerMove 25s linear infinite; white-space: nowrap; }
.ticker-item { display: inline-flex; align-items: center; gap: 10px; color: var(--text-white); font-size: 14px; font-weight: 500; }
.ticker-item .dot { width: 8px; height: 8px; background: var(--primary); border-radius: 50%; }
.ticker-item a { color: var(--text-white); transition: var(--transition); }
.ticker-item a:hover { color: var(--primary); }
@keyframes tickerMove { 0% { transform: translateX(0); } 100% { transform: translateX(-50%); } }

/* --- HEADER (UPDATED for ticker spacing) --- */
header { position: fixed; top: 0; width: 100%; z-index: 1000; background: rgba(10, 14, 20, 0.98); backdrop-filter: blur(20px); border-bottom: 1px solid var(--border); padding: 0 5%; display: flex; justify-content: space-between; align-items: center; height: 80px; box-shadow: var(--shadow-sm); }
.header-widget-section { flex-shrink: 1; min-width: 0; }
.header-widget-section .widget { margin: 0; }
.header-widget-section .widget-content { display: flex; align-items: center; gap: 12px; }
.logo-area { display: flex; align-items: center; gap: 12px; text-decoration: none; }
.logo-icon { width: 48px; height: 48px; background: var(--gradient-main); border-radius: 14px; display: flex; align-items: center; justify-content: center; color: #000; font-weight: 800; font-size: 24px; box-shadow: 0 5px 20px rgba(212, 175, 55, 0.3); transition: transform 0.3s; }
.logo-area:hover .logo-icon { transform: rotate(-10deg) scale(1.1); }
.logo-text { font-size: 24px; font-weight: 800; background: var(--gradient-main); -webkit-background-clip: text; -webkit-text-fill-color: transparent; white-space: nowrap; }
.header-widget-section h1 { margin: 0; line-height: 1; }
.header-widget-section img { max-height: 50px; width: auto; }

nav { display: flex; flex-wrap: wrap; justify-content: flex-end; flex-shrink: 0; }
nav .widget { margin: 0; }
nav .widget-content { display: flex; flex-wrap: wrap; justify-content: flex-end; }
nav ul { list-style: none; padding: 0; margin: 0; display: flex; flex-wrap: wrap; }
nav li { margin-left: 30px; list-style: none; }
nav li a { text-decoration: none; color: #cbd5e1; font-weight: 600; font-size: 15px; transition: var(--transition); position: relative; white-space: nowrap; display: inline-block; }
nav li a:hover { color: var(--primary); }
nav li a::after { content: ''; position: absolute; bottom: -6px; left: 0; width: 0; height: 2px; background: var(--primary); transition: var(--transition); }
nav li a:hover::after { width: 100%; }

@media (max-width: 900px) { nav { display: none; } .logo-text { font-size: 20px; } .news-ticker-wrapper { margin-top: 70px; } }

/* --- HERO --- */
.hero { min-height: 100vh; display: flex; align-items: center; justify-content: center; text-align: center; position: relative; padding: 100px 5%; overflow: hidden; }
.hero-bg { position: absolute; top: 0; left: 0; width: 100%; height: 100%; object-fit: cover; opacity: 0.3; z-index: -1; }
.hero-overlay { position: absolute; top: 0; left: 0; width: 100%; height: 100%; background: radial-gradient(circle at 50% 0%, rgba(26, 32, 44, 0.8) 0%, rgba(10, 14, 20, 0.95) 70%); z-index: -1; }
.hero-content { max-width: 800px; z-index: 1; animation: fadeInUp 1s ease-out; }
.badge { display: inline-flex; align-items: center; gap: 10px; background: rgba(212, 175, 55, 0.1); color: var(--primary); padding: 10px 25px; border-radius: 50px; font-size: 14px; font-weight: 700; border: 1px solid var(--primary); margin-bottom: 30px; backdrop-filter: blur(5px); }
.badge span { width: 8px; height: 8px; background: var(--primary); border-radius: 50%; animation: pulse 2s infinite; }
@keyframes pulse { 0% { opacity: 1; } 50% { opacity: 0.5; } 100% { opacity: 1; } }

@keyframes fadeInUp { from { opacity: 0; transform: translateY(30px); } to { opacity: 1; transform: translateY(0); } }
.hero h1 { font-size: clamp(40px, 6vw, 70px); font-weight: 800; margin: 0 0 25px 0; line-height: 1.1; }
.hero h1 span { background: var(--gradient-main); -webkit-background-clip: text; -webkit-text-fill-color: transparent; }
.hero p { font-size: 20px; color: var(--text-muted); margin-bottom: 40px; max-width: 600px; margin-left: auto; margin-right: auto; }
.hero-buttons { display: flex; gap: 20px; justify-content: center; flex-wrap: wrap; }

/* --- ABOUT US --- */
.about-grid { display: grid; grid-template-columns: 1fr 1fr; gap: 60px; align-items: center; }
.about-image { position: relative; border-radius: 30px; overflow: hidden; box-shadow: var(--shadow-lg); }
.about-image img { width: 100%; height: auto; display: block; transition: transform 0.5s; }
.about-image:hover img { transform: scale(1.05); }
.about-image::before { content: ''; position: absolute; top: -20px; left: -20px; right: 20px; bottom: 20px; border: 2px solid var(--primary); border-radius: 30px; z-index: -1; opacity: 0.3; }
.about-content h3 { font-size: 36px; margin-bottom: 20px; }
.about-content p { color: var(--text-muted); margin-bottom: 30px; line-height: 1.8; }
.about-features { display: grid; grid-template-columns: 1fr 1fr; gap: 20px; }
.feature-item { display: flex; align-items: center; gap: 15px; background: var(--card-bg); padding: 15px; border-radius: 12px; border: 1px solid var(--border); backdrop-filter: blur(10px); transition: var(--transition); }
.feature-item:hover { border-color: var(--primary); transform: translateX(5px); }
.feature-item .icon { font-size: 24px; }
.feature-item span { font-weight: 600; font-size: 14px; }
@media (max-width: 768px) { .about-grid { grid-template-columns: 1fr; } .about-features { grid-template-columns: 1fr; } }

/* --- SERVICES (Enhanced Cards) --- */
.services-section-bg { background: #0d1117; }
.services-grid { display: grid; grid-template-columns: repeat(auto-fit, minmax(300px, 1fr)); gap: 30px; }
.service-card { background: var(--card-bg); padding: 35px; border-radius: 24px; border: 1px solid var(--border-light); transition: var(--transition); text-align: left; position: relative; overflow: hidden; backdrop-filter: blur(10px); }
.service-card::before { content: ''; position: absolute; top: 0; left: 0; width: 100%; height: 3px; background: var(--gradient-main); opacity: 0; transition: var(--transition); }
.service-card:hover { border-color: rgba(212, 175, 55, 0.4); transform: translateY(-10px); box-shadow: var(--shadow-lg); }
.service-card:hover::before { opacity: 1; }
.service-icon { width: 70px; height: 70px; background: rgba(212, 175, 55, 0.1); color: var(--primary); border-radius: 20px; display: flex; align-items: center; justify-content: center; font-size: 32px; margin-bottom: 25px; transition: var(--transition); }
.service-card:hover .service-icon { background: var(--primary); color: #000; transform: rotate(-5deg) scale(1.1); }
.service-card h3 { font-size: 22px; color: #fff; margin-bottom: 15px; }
.service-card p { color: var(--text-muted); font-size: 15px; line-height: 1.6; }

/* --- PORTFOLIO with Popup --- */
.portfolio-grid { display: grid; grid-template-columns: repeat(auto-fit, minmax(300px, 1fr)); gap: 25px; }
.portfolio-item { position: relative; border-radius: 20px; overflow: hidden; height: 300px; border: 1px solid var(--border); cursor: pointer; transition: var(--transition); }
.portfolio-item img { width: 100%; height: 100%; object-fit: cover; transition: transform 0.5s; }
.portfolio-item:hover { border-color: var(--primary); box-shadow: var(--shadow-lg); }
.portfolio-item:hover img { transform: scale(1.1); }
.portfolio-overlay { position: absolute; top: 0; left: 0; width: 100%; height: 100%; background: linear-gradient(to top, rgba(0,0,0,0.95) 0%, transparent 100%); display: flex; align-items: flex-end; padding: 25px; opacity: 0; transition: var(--transition); }
.portfolio-item:hover .portfolio-overlay { opacity: 1; }
.portfolio-info h3 { color: #fff; margin: 0 0 5px 0; font-size: 20px; }
.portfolio-info p { color: var(--primary); font-size: 14px; font-weight: 600; margin-bottom: 10px; }
.view-project-btn { display: inline-block; background: var(--primary); color: #000; padding: 8px 20px; border-radius: 20px; font-size: 12px; font-weight: 700; text-transform: uppercase; transition: var(--transition); border: none; cursor: pointer; }
.view-project-btn:hover { background: #fff; color: #000; transform: scale(1.05); }

/* --- POPUP MODAL STYLES --- */
.modal-overlay { position: fixed; top: 0; left: 0; width: 100%; height: 100%; background: rgba(0,0,0,0.96); z-index: 2000; display: none; justify-content: center; align-items: center; opacity: 0; transition: opacity 0.3s; padding: 20px; }
.modal-overlay.active { display: flex; opacity: 1; }
.modal-box { background: var(--bg-dark); border: 1px solid var(--primary); border-radius: 30px; max-width: 1000px; width: 100%; max-height: 90vh; overflow-y: auto; position: relative; transform: scale(0.9); transition: transform 0.4s ease; box-shadow: 0 30px 80px rgba(212,175,55,0.2); }
.modal-overlay.active .modal-box { transform: scale(1); }
.modal-close { position: absolute; top: 15px; right: 20px; font-size: 30px; color: #fff; cursor: pointer; z-index: 10; background: rgba(0,0,0,0.5); width: 45px; height: 45px; border-radius: 50%; display: flex; align-items: center; justify-content: center; line-height: 1; transition: var(--transition); border: 1px solid var(--border); }
.modal-close:hover { background: var(--primary); color: #000; transform: rotate(90deg); }
.modal-img-container { width: 100%; height: 400px; overflow: hidden; border-radius: 30px 30px 0 0; }
.modal-img { width: 100%; height: 100%; object-fit: cover; }
.modal-body { padding: 40px; }
.modal-title { font-size: 32px; margin-bottom: 20px; color: var(--primary); font-weight: 800; }
.modal-text { color: var(--text-muted); line-height: 1.8; font-size: 16px; white-space: pre-line; }
@media (max-width:600px){ .modal-img-container{height:250px} .modal-body{padding:25px} }

/* --- GALLERY SLIDER (Infinite) --- */
.gallery-section { background: #0d1117; overflow: hidden; padding: 80px 5%; }
.slider-container { width: 100%; position: relative; padding: 20px 0; }
.slider-wrapper { display: flex; gap: 20px; animation: scroll 40s linear infinite; width: fit-content; }
.slider-wrapper:hover { animation-play-state: paused; }
.slide { min-width: 350px; height: 250px; border-radius: 20px; overflow: hidden; position: relative; border: 1px solid var(--border); flex-shrink: 0; box-shadow: var(--shadow-sm); }
.slide img { width: 100%; height: 100%; object-fit: cover; transition: transform 0.5s; }
.slide:hover img { transform: scale(1.1); }

@keyframes scroll { 0% { transform: translateX(0); } 100% { transform: translateX(calc(-350px * 4 - 80px)); } } /* adjust based on slide count */

@media (max-width: 600px) { .slide { min-width: 280px; height: 200px; } }

/* --- TEAM (Enhanced) --- */
.team-grid { display: grid; grid-template-columns: repeat(auto-fit, minmax(250px, 1fr)); gap: 30px; }
.team-card { background: var(--card-bg); border-radius: 24px; overflow: hidden; border: 1px solid var(--border); text-align: center; transition: var(--transition); backdrop-filter: blur(10px); }
.team-card:hover { transform: translateY(-10px); border-color: var(--primary); box-shadow: var(--shadow-lg); }
.team-img { height: 300px; overflow: hidden; position: relative; }
.team-img img { width: 100%; height: 100%; object-fit: cover; transition: transform 0.5s; }
.team-card:hover .team-img img { transform: scale(1.1); }
.team-info { padding: 25px; }
.team-info h3 { margin: 0 0 5px 0; font-size: 20px; }
.team-info p { color: var(--primary); font-size: 14px; margin-bottom: 15px; }
.team-social a { display: inline-flex; align-items: center; justify-content: center; width: 35px; height: 35px; background: rgba(255,255,255,0.05); border-radius: 50%; color: #fff; margin: 0 5px; transition: var(--transition); border: 1px solid var(--border); }
.team-social a:hover { background: var(--primary); color: #000; transform: translateY(-3px); }

/* --- TESTIMONIALS (New design) --- */
.testimonials-section-bg { background: linear-gradient(145deg, #0a0e14, #11151e); }
.testimonials-grid { display: grid; grid-template-columns: repeat(auto-fit, minmax(300px, 1fr)); gap: 30px; }
.testimonial-card { background: var(--card-bg); padding: 35px; border-radius: 30px; border: 1px solid var(--border); position: relative; backdrop-filter: blur(10px); transition: var(--transition); }
.testimonial-card:hover { border-color: var(--primary); transform: translateY(-5px); box-shadow: var(--shadow-lg); }
.testimonial-card::before { content: '“'; position: absolute; top: 20px; right: 30px; font-size: 100px; color: var(--primary); opacity: 0.1; font-family: serif; line-height: 1; }
.testimonial-text { color: var(--text-muted); font-size: 16px; line-height: 1.8; margin-bottom: 25px; font-style: italic; }
.testimonial-author { display: flex; align-items: center; gap: 15px; }
.author-img { width: 55px; height: 55px; border-radius: 50%; overflow: hidden; border: 2px solid var(--primary); padding: 3px; background: var(--bg-dark); }
.author-img img { width: 100%; height: 100%; object-fit: cover; border-radius: 50%; }
.author-info h4 { margin: 0; color: #fff; font-size: 16px; font-weight: 700; }
.author-info span { font-size: 13px; color: var(--primary); }

/* --- STATS (with counter animation placeholder) --- */
.stats-section { background: linear-gradient(145deg, #0a0e14 0%, #111111 100%); padding: 80px 5%; border-top: 1px solid var(--border); border-bottom: 1px solid var(--border); }
.stats-grid { display: grid; grid-template-columns: repeat(4, 1fr); gap: 30px; }
.stat-card { text-align: center; padding: 40px 20px; background: var(--card-bg); border-radius: 30px; border: 1px solid var(--border); transition: var(--transition); backdrop-filter: blur(10px); }
.stat-card:hover { transform: translateY(-8px); border-color: var(--primary); box-shadow: var(--shadow-lg); }
.stat-number { font-size: 52px; font-weight: 800; background: var(--gradient-main); -webkit-background-clip: text; -webkit-text-fill-color: transparent; line-height: 1.2; margin-bottom: 8px; }
.stat-label { color: var(--text-muted); font-size: 16px; font-weight: 600; text-transform: uppercase; letter-spacing: 1px; }
@media (max-width: 800px) { .stats-grid { grid-template-columns: repeat(2, 1fr); } }

/* --- BLOG (Homepage) --- */
.blog-grid { display: grid; grid-template-columns: repeat(auto-fit, minmax(280px, 1fr)); gap: 25px; }
.post-card { background: var(--card-bg); border-radius: 20px; overflow: hidden; border: 1px solid var(--border-light); transition: var(--transition); backdrop-filter: blur(10px); }
.post-card:hover { transform: translateY(-5px); border-color: var(--primary); box-shadow: var(--shadow-lg); }
.post-thumb { height: 200px; overflow: hidden; position: relative; }
.post-thumb img { width: 100%; height: 100%; object-fit: cover; transition: transform 0.5s; }
.post-card:hover .post-thumb img { transform: scale(1.1); }
.post-info { padding: 25px; }
.post-info h3 { margin: 0 0 10px 0; font-size: 20px; line-height: 1.4; }
.post-info h3 a { color: #fff; transition: var(--transition); }
.post-info h3 a:hover { color: var(--primary); }
.post-meta { font-size: 13px; color: var(--text-muted); margin-bottom: 15px; display: flex; gap: 15px; }
.post-meta i { margin-right: 5px; color: var(--primary); }
.read-more { color: var(--primary); font-weight: 700; text-decoration: none; font-size: 15px; display: inline-flex; align-items: center; gap: 5px; transition: var(--transition); }
.read-more:hover { gap: 10px; color: #fff; }

/* --- CONTACT & MAP (Enhanced) --- */
.contact-section { background: #0a0e14; padding: 100px 5%; }
.contact-grid { display: grid; grid-template-columns: 1fr 1fr; gap: 50px; }
.contact-form-container { background: var(--card-bg); border-radius: 40px; padding: 50px; border: 1px solid var(--border); backdrop-filter: blur(10px); box-shadow: var(--shadow-lg); }
.contact-form-container input, .contact-form-container textarea { width: 100%; padding: 16px 22px; margin-bottom: 22px; background: rgba(0,0,0,0.4); border: 1px solid var(--border); border-radius: 50px; color: var(--text-white); font-family: inherit; font-size: 16px; transition: var(--transition); }
.contact-form-container textarea { border-radius: 30px; resize: vertical; }
.contact-form-container input:focus, .contact-form-container textarea:focus { outline: none; border-color: var(--primary); box-shadow: 0 0 0 3px rgba(212,175,55,0.2); }
.map-container { border-radius: 40px; overflow: hidden; height: 100%; min-height: 450px; border: 1px solid var(--border); box-shadow: var(--shadow-lg); }
.map-container iframe { width: 100%; height: 100%; border: 0; }
@media (max-width: 900px) { .contact-grid { grid-template-columns: 1fr; } }

/* --- FOOTER (Enhanced) --- */
footer { background: var(--bg-darker); padding: 80px 5% 30px; border-top: 1px solid var(--primary); }
.footer-content { display: grid; grid-template-columns: repeat(auto-fit, minmax(250px, 1fr)); gap: 50px; margin-bottom: 50px; }
footer .widget { margin: 0; }
footer .widget > h2 { display: none; }
footer .widget-content { color: var(--text-muted); font-size: 15px; }
.footer-col h4 { color: var(--primary); margin-bottom: 25px; font-size: 20px; font-weight: 800; position: relative; padding-bottom: 10px; }
.footer-col h4::after { content: ''; position: absolute; bottom: 0; left: 0; width: 50px; height: 2px; background: var(--primary); }
.footer-links a { display: block; color: var(--text-muted); margin-bottom: 12px; transition: var(--transition); }
.footer-links a:hover { color: #fff; padding-left: 8px; }
.footer-bottom { text-align: center; padding-top: 30px; border-top: 1px solid rgba(255,255,255,0.05); font-size: 14px; color: var(--text-muted); }

/* --- BACK TO TOP --- */
.back-to-top { position: fixed; bottom: 30px; right: 30px; width: 55px; height: 55px; background: var(--gradient-main); border-radius: 50%; display: flex; align-items: center; justify-content: center; color: #000; font-size: 24px; font-weight: bold; text-decoration: none; box-shadow: 0 5px 25px rgba(212, 175, 55, 0.5); transition: var(--transition); z-index: 99; border: none; }
.back-to-top:hover { transform: translateY(-8px) scale(1.1); }

/* ========== REDESIGNED SINGLE POST PAGE ========== */
.post-view-container { max-width: 1000px; margin: 120px auto 60px; padding: 0 25px; }
.single-post-card { background: var(--card-bg); border-radius: 40px; border: 1px solid var(--border); overflow: hidden; backdrop-filter: blur(10px); box-shadow: var(--shadow-lg); }
.post-header { padding: 40px 40px 20px; text-align: center; border-bottom: 1px solid var(--border-light); }
.post-header h1 { font-size: 42px; color: #fff; margin: 20px 0 15px; line-height: 1.3; }
.post-meta-single { display: flex; justify-content: center; gap: 30px; color: var(--text-muted); font-size: 15px; flex-wrap: wrap; }
.post-meta-single span i { color: var(--primary); margin-right: 8px; }
.featured-image-single { width: 100%; max-height: 500px; overflow: hidden; border-radius: 30px; margin: 20px 40px; box-shadow: var(--shadow-lg); border: 1px solid var(--border); }
.featured-image-single img { width: 100%; height: auto; display: block; }
.post-body-content { padding: 30px 40px 40px; color: #e2e8f0; font-size: 17px; line-height: 1.9; }
.post-body-content h1, .post-body-content h2, .post-body-content h3 { color: var(--primary); margin-top: 30px; }
.post-body-content a { color: var(--primary); text-decoration: underline; }
.post-body-content a:hover { color: #fff; }
.post-body-content blockquote { border-left: 4px solid var(--primary); background: rgba(212,175,55,0.05); margin: 30px 0; padding: 20px 30px; font-style: italic; border-radius: 10px; }
.post-body-content img { max-width: 100%; height: auto; border-radius: 20px; margin: 20px 0; box-shadow: var(--shadow-sm); }

.post-footer-single { padding: 30px 40px 40px; border-top: 1px solid var(--border-light); }
.post-tags { display: flex; gap: 10px; flex-wrap: wrap; margin-bottom: 30px; }
.post-tags a { background: rgba(212,175,55,0.1); color: var(--primary); padding: 8px 18px; border-radius: 50px; font-size: 14px; border: 1px solid var(--border); transition: var(--transition); }
.post-tags a:hover { background: var(--primary); color: #000; border-color: var(--primary); }
.post-share { display: flex; align-items: center; gap: 15px; flex-wrap: wrap; margin-bottom: 35px; }
.post-share span { font-weight: 700; color: #fff; }
.share-icons { display: flex; gap: 10px; }
.share-icon { width: 45px; height: 45px; background: rgba(255,255,255,0.05); border-radius: 50%; display: flex; align-items: center; justify-content: center; color: #fff; border: 1px solid var(--border); transition: var(--transition); font-size: 18px; }
.share-icon:hover { background: var(--primary); color: #000; transform: translateY(-3px); }

.post-author-box { display: flex; gap: 25px; background: rgba(0,0,0,0.3); padding: 30px; border-radius: 30px; margin: 30px 0; border: 1px solid var(--border); }
.author-avatar { width: 90px; height: 90px; border-radius: 50%; overflow: hidden; border: 3px solid var(--primary); flex-shrink: 0; }
.author-avatar img { width: 100%; height: 100%; object-fit: cover; }
.author-details h4 { font-size: 22px; margin: 0 0 10px; color: #fff; }
.author-details p { color: var(--text-muted); margin: 0 0 15px; }
.author-details a { color: var(--primary); font-weight: 600; }

.comments-section { background: var(--card-bg); border-radius: 40px; padding: 40px; margin-top: 50px; border: 1px solid var(--border); }
.comments-section h3 { font-size: 28px; color: var(--primary); margin-bottom: 30px; text-align: center; }
#comment-editor { background: #fff; border-radius: 20px; min-height: 250px; }
.comment-form iframe { width: 100%; border-radius: 20px; background: #fff; }

.post-navigation { display: flex; justify-content: space-between; margin-top: 40px; gap: 20px; }
.post-nav-item { flex: 1; background: rgba(255,255,255,0.03); padding: 20px; border-radius: 20px; border: 1px solid var(--border); transition: var(--transition); }
.post-nav-item:hover { border-color: var(--primary); background: rgba(212,175,55,0.05); }
.post-nav-item .label { color: var(--primary); font-size: 14px; text-transform: uppercase; letter-spacing: 1px; display: block; margin-bottom: 5px; }
.post-nav-item .title { color: #fff; font-weight: 600; }

@media (max-width:700px){ 
    .post-header{padding:30px 20px} .post-body-content{padding:20px} .post-footer-single{padding:20px} 
    .post-author-box{flex-direction:column;align-items:center;text-align:center} 
    .post-navigation{flex-direction:column}
}

/* --- Additional Animations --- */
.fade-in { animation: fadeIn 1s ease; }
@keyframes fadeIn { from { opacity: 0; } to { opacity: 1; } }

body.script:
//
function openModal(el) {
    var title = el.getAttribute('data-title');
    var img = el.getAttribute('data-img');
    var desc = el.getAttribute('data-desc');

    document.getElementById('modalTitle').innerText = title;
    document.getElementById('modalImg').src = img;
    document.getElementById('modalText').innerText = desc;
    document.getElementById('projectModal').classList.add('active');
    document.body.style.overflow = 'hidden';
}

function closeModal(e) {
    if(!e || e.target.id === 'projectModal') {
        document.getElementById('projectModal').classList.remove('active');
        document.body.style.overflow = 'auto';
    }
}

// Optional: pause ticker on hover (already in CSS)
